SET NAMES utf8mb4;

DROP TABLE IF EXISTS dota2_players;
DROP TABLE IF EXISTS dota2_users;

CREATE TABLE dota2_players (id VARCHAR(64) PRIMARY KEY, wx_nickname VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, game_id VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, steam_id VARCHAR(100), calibrate_rank_name VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, calibrate_rank_label VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, calibrate_rank_star INT DEFAULT 0, calibrate_rank_sort INT DEFAULT 0, calibrate_mmr INT DEFAULT NULL, good_at_positions VARCHAR(200), signup_position VARCHAR(200), avatar_url VARCHAR(500), created_at BIGINT, updated_at BIGINT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE dota2_users (id VARCHAR(64) PRIMARY KEY, openid VARCHAR(64) UNIQUE, role VARCHAR(20) DEFAULT "user", nick_name VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, nick_change_count INT DEFAULT 0, created_at BIGINT, updated_at BIGINT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


GRANT ALL PRIVILEGES ON dota2.* TO 'dota2'@'localhost';
FLUSH PRIVILEGES;